import React, { useEffect, useState } from "react";
import { Link, useNavigate } from 'react-router-dom';
import DataTable from "react-data-table-component";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt } from "../../../utils/Common";
import { CButton, CFormLabel } from "@coreui/react";
import { createMetaJobDescription, deleteJobDescription, deletePosition, fetchAllJobDescriptionData, fetchAllPositionData } from "../../../components/services/CareerApi";
import { tableJobDescriptionConstant } from "./tableJobDescriptionConstant";
import { customStyles } from "../../../utils/tableCustomStyles";
import ExportCSV from "../../../utils/ExportCsvButton";
import Select from 'react-select';
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);

const openNewPositionModalSwal = (positionName) => {
    return ({
        title: `<h5>Are you sure you have a vacancy for the position ${positionName}?</h5>`,
        focusConfirm: false,
        type: 'warning',
        showCancelButton: true,
        confirmButtonText: 'Proceed',
        cancelButtonText: 'Cancel',
        allowOutsideClick: false,
    })
}

const jobTypeOptions = [
    { value: 'ALL', label: 'All' },
    { value: 'FULL_TIME', label: 'Full Time' },
    { value: 'INTERN', label: 'Intern' }
  ]; 

const headers = [
    { label: "Position Type", key: "jobType" },
    { label: "Position", key: "position" },
    { label: "Created Date", key: "createTime" },
    { label: "Status", key: "status"},
    { label: "No.of open positions", key: "openPositionCount"}
];

function JobDescriptionList() {
    const [rowData, setRowData] = useState([]);
    const [jobType, setJobType] = useState({value: "ALL", label: "All"})

    useEffect(() => {
        fetchJobDescriptionList();
    }, [jobType]);

    const fetchJobDescriptionList = async () =>{
        let response = await fetchAllJobDescriptionData(jobType?.value);
        let data = [];
        if(response?.code === 200){
            response?.results && response?.results.map((item) => {
                item.createTime = epochTogmt(item.createTime);
                data.push(item);
            })
            setRowData(data);
        }
    }

    const handleOpenPositionOrDelete = async (id, type) => {
        let response = {};
        if(type === "DELETE") {
            response = await deleteJobDescription(id);
        } else {
            response = await createMetaJobDescription({"jobDescriptionId": id});
        }
        if(response?.code === 200 || response?.code === 201) {
            fetchJobDescriptionList();
        }
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleOpenPositionOrDelete(id, "DELETE");
            }
        };
        handleConfirm();
    };

    const handleOpenNewPosition = (id, positionName) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(openNewPositionModalSwal(positionName));
            if (swalval && swalval.value === true) {
                handleOpenPositionOrDelete(id, "POSITION");
            }
        };
        handleConfirm();
    };

    const actionButton = () => {
        return (
            <React.Fragment>
               {authService.getPermission("JOB_DESCRIPTION_EXPORT_CSV") && rowData.length > 0 && <ExportCSV headers={headers} data={rowData} filename="jd_list" />}
            </React.Fragment>
        );
    };

    const handleSelectChange = (data) => {
        setJobType(data);
    }

    return (<div className='row'>
        <div className="col-md-12 mb-3">
            <div className="filterSection">
                <div className="col-md-3">
                    <Select
                        options={jobTypeOptions}
                        placeholder={"Filter by status"}
                        value={jobType}
                        onChange={handleSelectChange}
                        classNamePrefix="select"
                        styles={{
                            option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                const color = '#03a68059';
                                return {
                                    ...styles,
                                    backgroundColor: isDisabled
                                        ? null
                                        : isSelected
                                            ? '#03a68059'
                                            : isFocused
                                                ? '#03a68059'
                                                : null,
                                    color: isDisabled
                                        ? '#ccc'
                                        : isSelected
                                            ? color > 2
                                                ? '#00374d'
                                                : '#00374d'
                                            : data.color,
                                    cursor: isDisabled ? 'not-allowed' : 'default',

                                    ':active': {
                                        ...styles[':active'],
                                        backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                    },
                                };
                            },
                        }}
                    />
                </div>
            </div>
        </div>

        <div className="col2Large">
            <DataTable
                title="JD"
                columns={tableJobDescriptionConstant(fetchJobDescriptionList, handleConfirmModal, handleOpenNewPosition)}
                data={rowData}
                customStyles={customStyles}
                actions={actionButton()}
                pagination
                paginationPerPage={10}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
            />
        </div>
       {authService.getPermission("JOB_DESCRIPTION_CREATE") && <div className='col-sm-12'>
            <Link to={"/career/job-description/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create JD"}
                </CButton>
            </Link>
        </div>}
    </div>)
}

export default JobDescriptionList;
